package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetSkipHeaderRecordTrue() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null,
                false, true, "\r\n", null, null, true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecordFalse() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null,
                false, true, "\r\n", null, null, false);
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testGetSkipHeaderRecordDefaultFalse() {
        assertFalse(CSVFormat.DEFAULT.getSkipHeaderRecord());
    }

}
